func splitDomains(raw string) []string {
	if raw == "" {
		return nil
	}
	parts := strings.Split(raw, ",")
	out := parts[:0]
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

func secretPlaceholder(row entity.SSOProvider) string {
	if row.ClientSecret == "" {
		return "Paste the OAuth client secret"
	}
	return "•••••••• (set — leave blank to keep)"
}

